const launch = $('Get Retrospective Launches').item.json;
const briefs = $('Load All Briefs').all().map(i => i.json);
const readiness = $('Load Readiness History').all().map(i => i.json);
const decayReports = $('Load Decay Reports').all().map(i => i.json);

const totalBriefs = briefs.length;
const totalSignals = briefs.reduce((sum, b) => sum + (b.signal_count || 0), 0);
const peakReadiness = readiness.length > 0 ? Math.max(...readiness.map(r => r.score)) : launch.readiness_score;
const finalMomentum = decayReports.length > 0 ? decayReports[decayReports.length - 1].momentum_status : 'holding';

// Build readiness arc
const readinessArc = readiness.map(r => `${r.check_date}: ${r.score}/100`).join('\n');

// Build decay summary
const decaySummary = decayReports.map(d => `Week ${d.week_number}: drift=${d.messaging_drift_score}%, responses=${d.competitor_response_count}, momentum=${d.momentum_status}`).join('\n');

// Key learnings
const learnings = [];
if (peakReadiness < 70) learnings.push('Launch readiness never reached 70%. Consider extending pre-launch intelligence gathering for future launches.');
if (finalMomentum === 'fading') learnings.push('Post-launch momentum faded. Consider stronger follow-up campaigns or competitive responses.');
if (finalMomentum === 'strong') learnings.push('Launch maintained strong momentum through all 4 weeks. Replicate this approach.');
if (totalSignals < 10) learnings.push('Low signal volume. Increase competitor monitoring frequency before next launch.');
if (totalBriefs > 15) learnings.push('Extensive briefing coverage. This level of intelligence gathering supported good decision-making.');

const playbookTitle = `Retrospective Playbook — ${launch.launch_name}`;
const playbookMd = `# ${playbookTitle}\n**Product:** ${launch.product_name}\n**Launch Type:** ${launch.launch_type}\n**Target Date:** ${launch.target_launch_date}\n**Actual Date:** ${launch.actual_launch_date || 'N/A'}\n**Final Momentum:** ${finalMomentum}\n\n---\n\n## Launch Summary\n- **${totalBriefs}** briefs generated across the lifecycle\n- **${totalSignals}** competitive signals consumed\n- **Peak readiness:** ${peakReadiness}/100\n- **Competitors tracked:** ${(launch.competitor_names || []).join(', ') || 'None'}\n\n## Readiness Arc\n${readinessArc || 'No readiness checks recorded'}\n\n## Post-Launch Decay\n${decaySummary || 'No decay reports recorded'}\n\n## Key Learnings\n${learnings.map((l, i) => `${i + 1}. ${l}`).join('\n') || 'No specific learnings identified.'}\n\n## Recommendations for Next Launch\n1. Start pre-launch intelligence gathering at least 14 days before target date\n2. Aim for readiness score of 80+ before proceeding to launch\n3. Monitor post-launch decay weekly and respond to competitor moves within 48 hours\n4. Use this playbook as a reference template for similar launch types\n\n---\n*Generated by Signal Plane Launch Operations*`;

return [{
  json: {
    launch_id: launch.launch_id,
    user_id: launch.user_id,
    playbook_title: playbookTitle,
    playbook_md: playbookMd,
    playbook_json: JSON.stringify({
      launch_summary: { total_briefs: totalBriefs, total_signals: totalSignals, peak_readiness: peakReadiness },
      readiness_arc: readiness,
      decay_summary: decayReports,
      learnings: learnings
    }),
    total_briefs: totalBriefs,
    total_signals: totalSignals,
    peak_readiness: peakReadiness,
    final_momentum: finalMomentum,
    learnings: learnings
  }
}];
